#include <bits/stdc++.h>
using namespace std;
using ll = long long;

void solve(long long R, long long G, long long B, long long N){
  ll ans = 0;
  for(ll r = 0; r <= N / R; ++r){
    for(ll g = 0; g <= (N - r * R) / G; ++g){
      if((N - r * R - g * G) % B == 0){
        ++ans;
      }
    }
  }
  cout << ans << endl;
}

// Generated by 1.1.4 https://github.com/kyuridenamida/atcoder-tools  (tips: You use the default template now. You can remove this line by using your custom template)
int main(){
    long long R;
    scanf("%lld",&R);
    long long G;
    scanf("%lld",&G);
    long long B;
    scanf("%lld",&B);
    long long N;
    scanf("%lld",&N);
    solve(R, G, B, N);
    return 0;
}
